2	
3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
23	const LOYALTY_DISCOUNT_RATE = 0.2;
24	const LOYALTY_YEARS_THRESHOLD = 2;
25	const CURSED_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const COMPONENT_BASE = 25;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	const CLAIM_DEDUCTIBLE = 100;
31	
32	const ITEM_BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	function isComponentType(type: string): boolean {
42	  return ITEM_BASE_PREMIUMS[type] === COMPONENT_BASE;
43	}
44	
45	function groupItemsByType(items: Item[]): Map<string, Item[]> {
46	  const groups = new Map<string, Item[]>();
47	  for (const item of items) {
48	    const group = groups.get(item.type) ?? [];
49	    group.push(item);
50	    groups.set(item.type, group);
51	  }
52	  return groups;
53	}
54	
55	function totalSurchargeRate(item: Item): number {
56	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
57	  const highEnchantmentRate =
58	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
59	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
60	      : 0;
61	  return cursedRate + highEnchantmentRate;
62	}
63	
64	function calculateItemSurcharge(type: string, item: Item): number {
65	  const base = ITEM_BASE_PREMIUMS[type];
66	  return base * totalSurchargeRate(item);
67	}
68	
69	function calculateGroupBase(type: string, group: Item[]): number {
70	  if (isComponentType(type) && group.length === 3) {
71	    return COMPONENT_BLOCK_PREMIUM;
72	  }
73	  return group.reduce((sum) => sum + ITEM_BASE_PREMIUMS[type], 0);
74	}
75	
76	function calculatePolicyBase(items: Item[]): number {
77	  const groups = groupItemsByType(items);
78	  return Array.from(groups).reduce(
79	    (total, [type, group]) => total + calculateGroupBase(type, group),
80	    0
81	  );
82	}
83	
84	function calculateItemSurcharges(items: Item[]): number {
85	  return items.reduce(
86	    (total, item) => total + calculateItemSurcharge(item.type, item),
87	    0
88	  );
89	}
90	
91	function calculateLoyaltyDiscount(customer: Customer, policyBase: number): number {
92	  if (customer.yearsWithMHPCO < LOYALTY_YEARS_THRESHOLD) {
93	    return 0;
94	  }
95	  return policyBase * LOYALTY_DISCOUNT_RATE;
96	}
97	
98	function calculateFollowUpDiscount(customer: Customer, policyBase: number): number {
99	  const hasPreviousContracts = (customer.previousContracts ?? 0) >= 1;
100	  if (!hasPreviousContracts) {
101	    return 0;
102	  }
103	  return policyBase * FOLLOW_UP_DISCOUNT_RATE;
104	}
105	
106	function calculateFirstInsuranceSurcharge(policyBase: number): number {
107	  return policyBase * FIRST_INSURANCE_RATE;
108	}
109	
110	export type Damage = {
111	  itemType: string;
112	  amount: number;
113	};
114	
115	export type Incident = {
116	  cause: string;
117	  damages: Damage[];
118	};
119	
120	export type PolicyState = {
121	  items: Item[];
122	  remainingCap: number;
123	};
124	
125	export type ClaimInput = {
126	  policy: PolicyState;
127	  incident: Incident;
128	};
129	
130	export type ClaimResult = {
131	  payout: number;
132	  remainingCap: number;
133	};
134	
135	export function claim(input: ClaimInput): ClaimResult {
136	  const damageAmount = input.incident.damages[0].amount;
137	  const payout = Math.max(damageAmount - CLAIM_DEDUCTIBLE, 0);
138	  return { payout, remainingCap: input.policy.remainingCap - payout };
139	}
140	
141	export function quote(input: QuoteInput): number {
142	  const policyBase = calculatePolicyBase(input.items);
143	  const itemSurcharges = calculateItemSurcharges(input.items);
144	  const firstInsuranceSurcharge = calculateFirstInsuranceSurcharge(policyBase);
145	  const loyaltyDiscount = calculateLoyaltyDiscount(input.customer, policyBase);
146	  const followUpDiscount = calculateFollowUpDiscount(input.customer, policyBase);
147	  return Math.ceil(
148	    policyBase +
149	      itemSurcharges +
150	      firstInsuranceSurcharge +
151	      PROCESSING_FEE -
152	      loyaltyDiscount -
153	      followUpDiscount
154	  );
155	}
