it("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)", () => {
  expect(
    claim({
      policy: {
        items: [{ type: "sword", material: "steel", enchantment: 9, cursed: false }],
        remainingCap: 2000,
      },
      incident: {
        cause: "dragon attack",
